def categorize_utensils(utensils):
    categories = {
        'kitchenware': [],
        'cookware': [],
        'ovenware': [],
        'bakeware': []
    }

    keywords = {
        'kitchenware': ['cutting board', 'peeler', 'mixing bowl'],
        'cookware': ['pot', 'pan', 'skillet'],
        'ovenware': ['baking sheet', 'roasting pan'],
        'bakeware': ['cake pan', 'pie dish', 'muffin tin']
    }

    for utensil in utensils:
        for category, words in keywords.items():
            if any(word in utensil.lower() for word in words):
                categories[category].append(utensil)
                break
        else:
            categories['kitchenware'].append(utensil)

    return categories

# Example usage:
utensils = ['chef knife', 'cast iron skillet', 'baking sheet', 'wooden spoon', 'loaf pan']
print(categorize_utensils(utensils))

This function categorizes utensils based on keywords associated with each category. If a utensil doesn't match any specific category, it defaults to 'kitchenware'.
